// Extract email content for LLM classification
const item = $input.first().json;

const subject = item.subject || '';
const from = item.from?.text || item.from || '';
const textBody = item.text || item.textPlain || '';
const htmlBody = item.html || '';

// Prefer text body, fall back to stripping HTML
let body = textBody;
if (!body && htmlBody) {
  body = htmlBody.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
}

// Truncate to avoid overloading the LLM
if (body.length > 2000) {
  body = body.substring(0, 2000) + '...';
}

return [{
  json: {
    subject,
    from,
    body,
    received_at: item.date || new Date().toISOString()
  }
}];

