// Parse LLM JSON response with fallback handling
const item = $input.first().json;
const prevData = $('Extract Content').first().json;

let parsed;
try {
  // Ollama returns { response: "...json string..." }
  const raw = item.response || '';
  parsed = JSON.parse(raw);
} catch (e) {
  // If JSON parsing fails, treat as non-reservation
  parsed = {
    is_reservation: false,
    name: '',
    date: '',
    time: '',
    party_size: null,
    phone_number: '',
    special_requests: '',
    parse_error: e.message
  };
}

return [{
  json: {
    ...parsed,
    // Carry forward email metadata
    email_from: prevData.from,
    email_subject: prevData.subject,
    received_at: prevData.received_at
  }
}];

// Format WhatsApp message for Ramona (German)
const d = $input.first().json;

const lines = [
  '*Neue Reservierungsanfrage per E-Mail*',
  ''
];

if (d.name) lines.push(`Name: ${d.name}`);
if (d.date) lines.push(`Datum: ${d.date}`);
if (d.time) lines.push(`Uhrzeit: ${d.time}`);
if (d.party_size) lines.push(`Personen: ${d.party_size}`);
if (d.phone_number) {
  lines.push(`Telefon: ${d.phone_number}`);
} else {
  lines.push('Telefon: _nicht angegeben_');
}
if (d.special_requests) {
  lines.push(`Sonderwuensche: ${d.special_requests}`);
}

lines.push('');
lines.push(`Absender: ${d.email_from}`);

return [{
  json: {
    ...d,
    whatsapp_message: lines.join('\n')
  }
}];
